import{_ as a,o as e,c as r,a2 as i}from"./chunks/framework.BEgbRHOA.js";const x=JSON.parse('{"title":"Клиентское приложение (xcourier)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/xcourier/index.md","filePath":"guide/xcourier/index.md","lastUpdated":1775746985000}'),d={name:"guide/xcourier/index.md"};function l(o,t,n,h,c,s){return e(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="клиентское-приложение-xcourier" tabindex="-1">Клиентское приложение (xcourier) <a class="header-anchor" href="#клиентское-приложение-xcourier" aria-label="Permalink to &quot;Клиентское приложение (xcourier)&quot;">​</a></h1><p>Мобильное приложение для покупателей. Позволяет просматривать каталоги магазинов, выбирать товары, оформлять заказы и отслеживать их доставку.</p><h2 id="для-кого" tabindex="-1">Для кого <a class="header-anchor" href="#для-кого" aria-label="Permalink to &quot;Для кого&quot;">​</a></h2><p>Конечные пользователи — жители города, которые хотят заказать продукты с доставкой на дом или самовывозом.</p><h2 id="основные-возможности" tabindex="-1">Основные возможности <a class="header-anchor" href="#основные-возможности" aria-label="Permalink to &quot;Основные возможности&quot;">​</a></h2><ul><li>Просмотр списка магазинов и их каталогов</li><li>Поиск товаров по названию</li><li>Фильтрация товаров по категориям</li><li>Корзина с подсчётом итоговой стоимости</li><li>Оформление заказа с выбором адреса доставки и способа оплаты</li><li>Отслеживание статуса заказа в реальном времени</li><li>Избранные магазины</li><li>Обращения в поддержку</li><li>Push-уведомления о смене статуса заказа</li></ul><h2 id="навигация-приложения" tabindex="-1">Навигация приложения <a class="header-anchor" href="#навигация-приложения" aria-label="Permalink to &quot;Навигация приложения&quot;">​</a></h2><p>Приложение использует нижнюю панель с четырьмя вкладками:</p><table tabindex="0"><thead><tr><th>Вкладка</th><th>Описание</th></tr></thead><tbody><tr><td>Главная</td><td>Список магазинов и баннеры</td></tr><tr><td>Избранное</td><td>Сохранённые магазины</td></tr><tr><td>Корзина</td><td>Товары для заказа</td></tr><tr><td>Профиль</td><td>Данные пользователя, история заказов, поддержка</td></tr></tbody></table><h2 id="авторизация" tabindex="-1">Авторизация <a class="header-anchor" href="#авторизация" aria-label="Permalink to &quot;Авторизация&quot;">​</a></h2><p>Пользователь может пользоваться приложением анонимно (просмотр каталога), но для оформления заказа необходима аутентификация через Firebase Auth.</p>',11)])])}const _=a(d,[["render",l]]);export{x as __pageData,_ as default};
